const item = $input.first().json;
const video_id = item.video_id || null;
if (!video_id) throw new Error('video_id não encontrado.');
return [{ json: { video_id } }];

// Buscar efeitos no banco para cada cena
const config = $('Configuração').first().json;
const videoId = $('Normalizar Input').first().json.video_id;
const cenasRaw = $('Ler Cenas').all().map(i => i.json);
const cenas = Array.isArray(cenasRaw[0]) ? cenasRaw[0] : cenasRaw;

const headers = {
  'apikey': config.SUPABASE_SERVICE_KEY,
  'Authorization': 'Bearer ' + config.SUPABASE_SERVICE_KEY
};

const faltantes = [];
const items = [];

for (const c of cenas) {
  // Parse efeitos_sonoros
  let efx = c.efeitos_sonoros;
  if (typeof efx === 'string') {
    try { efx = JSON.parse(efx); } catch(e) { efx = []; }
  }
  if (!Array.isArray(efx)) efx = [];

 // Pular cenas de texto (tela final, etc.)
  if (c.tipo_cena === 'texto') continue;

  // (cenas sem narração ainda podem ter efeitos sonoros)

  const resolvedEffects = [];

  for (const ef of efx) {
    if (ef.tipo === 'banco' && ef.tag) {
      // Buscar no banco: menos usado primeiro
      try {
        const result = await this.helpers.httpRequest({
          method: 'GET',
          url: config.SUPABASE_URL + '/rest/v1/banco_efeitos?tag=eq.' + encodeURIComponent(ef.tag) + '&order=uso_count.asc&limit=1',
          headers
        });
        if (result && result.length > 0) {
          resolvedEffects.push({
            tag: ef.tag,
            weight: ef.weight || 0.5,
            arquivo_url: result[0].arquivo_url,
            banco_id: result[0].id
          });
        } else {
          faltantes.push({ cena: c.numero, tag: ef.tag, tipo: 'banco' });
        }
      } catch(e) {
        faltantes.push({ cena: c.numero, tag: ef.tag, tipo: 'banco', erro: e.message });
      }
    } else if (ef.tipo === 'stable_audio') {
      // Stable Audio desabilitado — marcar como faltante
      faltantes.push({ cena: c.numero, tag: ef.prompt || 'stable_audio', tipo: 'stable_audio_desabilitado' });
    }
  }

items.push({
  json: {
    cenaId: c.id,
    cenaNumero: c.numero,
    tts_url: c.tts_url || null,
    duracao_real: c.duracao_real || 0,
    effects: resolvedEffects,
    _videoId: videoId
  }
});
}

// Salvar faltantes no staticData para verificação
var staticData = $getWorkflowStaticData('global');
staticData.faltantes = faltantes;
staticData.videoId = videoId;

// Retornar items + flag
return [{ json: {
  _temFaltantes: faltantes.length > 0,
  _faltantes: faltantes,
  _totalCenas: items.length,
  _items: items.map(i => i.json)
} }];

// Marcar cenas com efeitos faltantes no Supabase
const config = $('Configuração').first().json;
const faltantes = $('Buscar Efeitos no Banco').first().json._faltantes;
const videoId = $('Normalizar Input').first().json.video_id;

const headers = {
  'apikey': config.SUPABASE_SERVICE_KEY,
  'Authorization': 'Bearer ' + config.SUPABASE_SERVICE_KEY,
  'Content-Type': 'application/json',
  'Prefer': 'return=minimal'
};

// Marcar geracao_efeitos_status como concluido (parcial)
await this.helpers.httpRequest({
  method: 'PATCH',
  url: config.SUPABASE_URL + '/rest/v1/videos?id=eq.' + videoId,
  headers,
  body: { geracao_efeitos_status: 'concluido' }
});

const lista = faltantes.map(f => 'Cena ' + f.cena + ': ' + f.tag + ' (' + f.tipo + ')').join('\n');
throw new Error('❌ EFEITOS FALTANTES NO BANCO:\n\n' + lista + '\n\nAções:\n1. Baixe os efeitos de freesound.org ou pixabay.com\n2. Suba para o bucket banco-efeitos no Supabase\n3. Adicione na tabela banco_efeitos com a tag correta\n4. Re-dispare o M06');

// Preparar items para o loop
const data = $('Buscar Efeitos no Banco').first().json;
const items = data._items || [];
return items.map(i => ({ json: i }));

// Monta script FFmpeg para esta cena
const item = $('Loop Cenas').first().json;
const config = $('Configuração').first().json;
const videoId = $('Normalizar Input').first().json.video_id;
const dir = '/tmp/m06/' + videoId;
const effects = item.effects || [];
const hasNarr = !!item.tts_url;

let script = 'set -e\n';
script += 'cd ' + dir + '\n\n';

if (hasNarr) {
  // Download narração
  script += '# Download narração\n';
  script += 'curl -sL -o narr.mp3 "' + item.tts_url + '"\n\n';

  // Medir duração real da narração
  script += '# Medir duração\n';
  script += 'NARR_DUR=$(ffprobe -v quiet -show_entries format=duration -of csv=p=0 narr.mp3)\n\n';

  // Normalizar narração + atempo se > 5s + pad para 5s
  script += '# Normalizar narração + atempo se > 5s + pad para 5s\n';
  script += 'NEED_ATEMPO=$(python3 -c "d=float(\'$NARR_DUR\'); print(1 if d > 5.0 else 0)")\n';
  script += 'if [ "$NEED_ATEMPO" = "1" ]; then\n';
  script += '  ATEMPO_VAL=$(python3 -c "d=float(\'$NARR_DUR\'); print(round(d/5.0, 4))")\n';
  script += '  ffmpeg -y -i narr.mp3 -af "atempo=${ATEMPO_VAL},loudnorm=I=-16:TP=-1:LRA=11,apad=whole_dur=5" -t 5 -c:a libmp3lame -q:a 0 narr_proc.mp3\n';
  script += 'else\n';
  script += '  ffmpeg -y -i narr.mp3 -af "loudnorm=I=-16:TP=-1:LRA=11,apad=whole_dur=5" -t 5 -c:a libmp3lame -q:a 0 narr_proc.mp3\n';
  script += 'fi\n\n';
}

// Download e processar cada efeito
for (let i = 0; i < effects.length; i++) {
  const ef = effects[i];
  script += '# Efeito ' + i + ': ' + ef.tag + '\n';
  script += 'curl -sL -o fx_' + i + '.raw "' + ef.arquivo_url + '"\n';
  script += 'ffmpeg -y -i fx_' + i + '.raw -af "apad=whole_dur=5,afade=t=out:st=4.5:d=0.5" -t 5 -c:a libmp3lame -q:a 0 fx_' + i + '_proc.mp3\n\n';
}

// Mixar
const narrInputs = hasNarr ? 1 : 0;
const totalInputs = narrInputs + effects.length;
let weights = hasNarr ? '1.0' : '';
for (const ef of effects) {
  weights += (weights ? ' ' : '') + (ef.weight || 0.5);
}

if (totalInputs === 0) {
  // Sem nada — gerar silêncio de 5s
  script += '# Sem narração nem efeitos — silêncio\n';
  script += 'ffmpeg -y -f lavfi -i anullsrc=r=44100:cl=stereo -t 5 -c:a libmp3lame -q:a 0 mix.mp3\n\n';
} else if (totalInputs === 1 && hasNarr && effects.length === 0) {
  script += '# Só narração\n';
  script += 'cp narr_proc.mp3 mix.mp3\n\n';
} else if (totalInputs === 1 && !hasNarr && effects.length === 1) {
  script += '# Só um efeito\n';
  script += 'cp fx_0_proc.mp3 mix.mp3\n\n';
} else {
  script += '# Mixar\n';
  let inputs = '';
  if (hasNarr) inputs += '-i narr_proc.mp3';
  for (let i = 0; i < effects.length; i++) {
    inputs += (inputs ? ' ' : '') + '-i fx_' + i + '_proc.mp3';
  }
  script += 'ffmpeg -y ' + inputs + ' -filter_complex "amix=inputs=' + totalInputs + ':weights=' + weights + '" -t 5 -c:a libmp3lame -q:a 0 mix.mp3\n\n';
}

// Upload para Supabase Storage
const storagePath = videoId + '/fx_' + item.cenaNumero + '.mp3';
const uploadUrl = config.SUPABASE_URL + '/storage/v1/object/efeitos/' + storagePath;
const publicUrl = config.SUPABASE_URL + '/storage/v1/object/public/efeitos/' + storagePath;

script += '# Upload para Supabase\n';
script += 'curl -s -X POST "' + uploadUrl + '" ';
script += '-H "apikey: ' + config.SUPABASE_SERVICE_KEY + '" ';
script += '-H "Authorization: Bearer ' + config.SUPABASE_SERVICE_KEY + '" ';
script += '-H "Content-Type: audio/mpeg" ';
script += '-H "x-upsert: true" ';
script += '--data-binary @mix.mp3\n\n';

// Cleanup
script += '# Cleanup\n';
script += 'rm -f narr.mp3 narr_proc.mp3 fx_*.raw fx_*_proc.mp3 mix.mp3\n';

script += 'echo "SUCCESS"\n';

return [{ json: { _script: script, cenaId: item.cenaId, cenaNumero: item.cenaNumero, publicUrl, _videoId: videoId } }];

const sshOutput = $('Executar FFmpeg').first().json;
const meta = $('Montar Script FFmpeg').first().json;

// Verificar sucesso
const stdout = sshOutput.stdout || '';
const stderr = sshOutput.stderr || '';

if (!stdout.includes('SUCCESS')) {
  throw new Error('❌ FFmpeg ERRO na cena ' + meta.cenaNumero + ':\n' + stderr.substring(0, 500));
}

return [{ json: {
  cenaId: meta.cenaId,
  cenaNumero: meta.cenaNumero,
  videoId: meta.videoId,
  publicUrl: meta.publicUrl,
  bancoIds: meta.bancoIds
} }];

// Incrementar uso_count dos efeitos usados
const config = $('Configuração').first().json;
const meta = $('Verificar Resultado').first().json;
const bancoIds = meta.bancoIds || [];

