  'Content-Type': 'application/json',
  'Prefer': 'return=minimal'
};

for (const id of bancoIds) {
  try {
    // Ler uso_count atual
    const result = await this.helpers.httpRequest({
      method: 'GET',
      url: config.SUPABASE_URL + '/rest/v1/banco_efeitos?id=eq.' + id + '&select=uso_count',
      headers: { apikey: config.SUPABASE_SERVICE_KEY, Authorization: 'Bearer ' + config.SUPABASE_SERVICE_KEY }
    });
    const current = (result && result[0]) ? (result[0].uso_count || 0) : 0;
    // Incrementar
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: config.SUPABASE_URL + '/rest/v1/banco_efeitos?id=eq.' + id,
      headers,
      body: { uso_count: current + 1, ultima_vez: new Date().toISOString() }
    });
  } catch(e) {}
}

return [{ json: { _consolidado: true } }];

